import React, { useState } from 'react';
import { authAPI } from '../services/api';

const Login = ({ onLogin }) => {
  const [formData, setFormData] = useState({
    username: '',
    password: ''
  });
  const [isSignup, setIsSignup] = useState(false);
  const [signupData, setSignupData] = useState({
    username: '',
    email: '',
    password: '',
    role: 'CUSTOMER',
    restaurantName: '',
    restaurantLocation: ''
  });

  const handleLogin = async (e) => {
    e.preventDefault();
    try {
      const response = await authAPI.login(formData);
      localStorage.setItem('token', response.data.token);
      localStorage.setItem('user', JSON.stringify(response.data));
      onLogin(response.data);
    } catch (error) {
      alert('Login failed: ' + (error.response?.data || 'Unknown error'));
    }
  };

  const handleSignup = async (e) => {
    e.preventDefault();
    try {
      await authAPI.signup(signupData);
      alert('Registration successful! Please login.');
      setIsSignup(false);
      setSignupData({
        username: '',
        email: '',
        password: '',
        role: 'CUSTOMER',
        restaurantName: '',
        restaurantLocation: ''
      });
    } catch (error) {
      alert('Signup failed: ' + (error.response?.data || 'Unknown error'));
    }
  };

  return (
    <div className="min-h-screen bg-gray-100 flex items-center justify-center">
      <div className="max-w-md w-full bg-white rounded-lg shadow-md p-6">
        <h2 className="text-2xl font-bold text-center mb-6">
          {isSignup ? 'Sign Up' : 'Login'} - SnackSmart
        </h2>

        {!isSignup ? (
          <form onSubmit={handleLogin}>
            <div className="mb-4">
              <input
                type="text"
                placeholder="Username"
                className="w-full px-3 py-2 border rounded-lg focus:outline-none focus:border-blue-500"
                value={formData.username}
                onChange={(e) => setFormData({...formData, username: e.target.value})}
                required
              />
            </div>
            <div className="mb-6">
              <input
                type="password"
                placeholder="Password"
                className="w-full px-3 py-2 border rounded-lg focus:outline-none focus:border-blue-500"
                value={formData.password}
                onChange={(e) => setFormData({...formData, password: e.target.value})}
                required
              />
            </div>
            <button
              type="submit"
              className="w-full bg-blue-500 text-white py-2 rounded-lg hover:bg-blue-600"
            >
              Login
            </button>
          </form>
        ) : (
          <form onSubmit={handleSignup}>
            <div className="mb-4">
              <input
                type="text"
                placeholder="Username"
                className="w-full px-3 py-2 border rounded-lg focus:outline-none focus:border-blue-500"
                value={signupData.username}
                onChange={(e) => setSignupData({...signupData, username: e.target.value})}
                required
              />
            </div>
            <div className="mb-4">
              <input
                type="email"
                placeholder="Email"
                className="w-full px-3 py-2 border rounded-lg focus:outline-none focus:border-blue-500"
                value={signupData.email}
                onChange={(e) => setSignupData({...signupData, email: e.target.value})}
                required
              />
            </div>
            <div className="mb-4">
              <input
                type="password"
                placeholder="Password"
                className="w-full px-3 py-2 border rounded-lg focus:outline-none focus:border-blue-500"
                value={signupData.password}
                onChange={(e) => setSignupData({...signupData, password: e.target.value})}
                required
              />
            </div>
            <div className="mb-4">
              <select
                className="w-full px-3 py-2 border rounded-lg focus:outline-none focus:border-blue-500"
                value={signupData.role}
                onChange={(e) => setSignupData({...signupData, role: e.target.value})}
              >
                <option value="CUSTOMER">Customer</option>
                <option value="OWNER">Restaurant Owner</option>
              </select>
            </div>
            {signupData.role === 'OWNER' && (
              <>
                <div className="mb-4">
                  <input
                    type="text"
                    placeholder="Restaurant Name"
                    className="w-full px-3 py-2 border rounded-lg focus:outline-none focus:border-blue-500"
                    value={signupData.restaurantName}
                    onChange={(e) => setSignupData({...signupData, restaurantName: e.target.value})}
                    required
                  />
                </div>
                <div className="mb-6">
                  <input
                    type="text"
                    placeholder="Restaurant Location"
                    className="w-full px-3 py-2 border rounded-lg focus:outline-none focus:border-blue-500"
                    value={signupData.restaurantLocation}
                    onChange={(e) => setSignupData({...signupData, restaurantLocation: e.target.value})}
                    required
                  />
                </div>
              </>
            )}
            {signupData.role === 'CUSTOMER' && <div className="mb-6"></div>}
            <button
              type="submit"
              className="w-full bg-green-500 text-white py-2 rounded-lg hover:bg-green-600"
            >
              Sign Up
            </button>
          </form>
        )}

        <div className="mt-4 text-center">
          <button
            onClick={() => setIsSignup(!isSignup)}
            className="text-blue-500 hover:underline"
          >
            {isSignup ? 'Already have an account? Login' : 'Need an account? Sign Up'}
          </button>
        </div>
      </div>
    </div>
  );
};

export default Login;
